package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowToCollectionDestinationTest : TestBase() {

    @Test
    fun testSharedFlowToListFillsDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(extraBufferCapacity = 16)
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(acc)
        }

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        // Ensure collector had a chance to process emissions before cancellation
        repeat(100) {
            if (acc.size == 3) return@repeat
            yield()
        }

        job.cancelAndJoin()
        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test
    fun testSharedFlowToSetFillsDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(extraBufferCapacity = 16)
        val acc = linkedSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toSet(acc)
        }

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(2)

        repeat(100) {
            if (acc.size == 2) return@repeat
            yield()
        }

        job.cancelAndJoin()
        assertEquals(setOf(1, 2), acc)
    }
}
"}

